mapper.select:
SELECT cm.id AS messageId, cm.from_user_id AS fromUserId, u.username AS fromUserName, u.avatar AS fromUserAvatar, cm.to_user_id AS toUserId, cm.message_type AS messageType, cm.message AS content, cm.is_read AS isRead, cm.create_time AS createTime FROM chat_message cm LEFT JOIN user u ON cm.from_user_id = u.id WHERE ((cm.from_user_id = #{currentUserId} AND cm.to_user_id = #{toUserId}) OR (cm.from_user_id = #{toUserId} AND cm.to_user_id = #{currentUserId}))
AND cm.product_id = #{productId}
ORDER BY cm.create_time DESC

